import{_ as a,o,c as r,a2 as e}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"1975年 核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1975年/核心总结.md","filePath":"01_letters/1975年/核心总结.md"}'),d={name:"01_letters/1975年/核心总结.md"};function l(n,t,s,i,h,p){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_1975年-核心总结" tabindex="-1">1975年 核心总结 <a class="header-anchor" href="#_1975年-核心总结" aria-label="Permalink to &quot;1975年 核心总结&quot;">​</a></h1><blockquote><p><strong>一句话总结：</strong> 营业利润671万美元，ROE仅7.6%，是1967年以来最差的回报率。但这是黎明前最后的黑暗——本土州保险盈利改善，K&amp;W化工和喜诗糖果的权益都在扩大，1976年即将迎来显著反弹。</p></blockquote><h2 id="核心数据" tabindex="-1">核心数据 <a class="header-anchor" href="#核心数据" aria-label="Permalink to &quot;核心数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>1975年</th><th>对比</th></tr></thead><tbody><tr><td>营业利润</td><td>671万美元</td><td>大幅下滑</td></tr><tr><td>每股收益</td><td>$6.85</td><td>1967年以来最低</td></tr><tr><td>ROE</td><td><strong>7.6%</strong></td><td>1967年来最低</td></tr><tr><td>联邦所得税退税</td><td><strong>大额</strong></td><td>不可持续的收益</td></tr><tr><td>纺织品产量</td><td>最大降幅53%</td><td>几近停工</td></tr></tbody></table><h2 id="灾难性衰退后的行业底部" tabindex="-1">灾难性衰退后的行业底部 <a class="header-anchor" href="#灾难性衰退后的行业底部" aria-label="Permalink to &quot;灾难性衰退后的行业底部&quot;">​</a></h2><p>1975年上半年，纺织产品销售极度低迷，公司被迫将生产规模缩减53%。旺贝克纺织厂的收购更是雪上加霜——收购时已经亏损，织机开工率仅55%。</p><p>但危机的底部，孕育了复苏的种子。</p><p><strong>&quot;V型&quot;衰退的快速反弹</strong></p><p>与大多数纺织周期不同，1975年生产商迅速减产，避免了大规模库存积压。结果是：当需求回暖时，工厂端能够快速跟上。旺贝克在收购后数月内实现了盈亏平衡，全年扭亏为盈。</p><p>Ken Chace 团队的管理能力再次得到了验证：在最恶劣的环境下，仍能找到出路。</p><h2 id="保险-最黑暗的时刻-也是转折的前夜" tabindex="-1">保险：最黑暗的时刻，也是转折的前夜 <a class="header-anchor" href="#保险-最黑暗的时刻-也是转折的前夜" aria-label="Permalink to &quot;保险：最黑暗的时刻，也是转折的前夜&quot;">​</a></h2><h3 id="全行业陷入泥沼" tabindex="-1">全行业陷入泥沼 <a class="header-anchor" href="#全行业陷入泥沼" aria-label="Permalink to &quot;全行业陷入泥沼&quot;">​</a></h3><p>1975年是财产意外伤害险行业&quot;史上最糟糕的一年&quot;。三重打击：</p><ol><li><strong>经济通胀</strong>：赔付成本（修车、医疗）涨幅远超一般通胀</li><li><strong>社会通胀</strong>：陪审团判赔金额扩大，诉讼频率上升</li><li><strong>供给侧危机</strong>：大量保险公司破产，担保基金让幸存者分摊损失</li></ol><p>伯克希尔的保险业务恰好集中在最惨烈的赛道：汽车险和长尾责任险。</p><h3 id="唯一的亮点-本土州保险" tabindex="-1">唯一的亮点：本土州保险 <a class="header-anchor" href="#唯一的亮点-本土州保险" aria-label="Permalink to &quot;唯一的亮点：本土州保险&quot;">​</a></h3><blockquote><p>&quot;本土州业务唯一实现改善的保险板块。&quot;</p><p>&quot;玉米壳意外伤害保险公司，综合成本率仅略低于100。&quot;</p><p>&quot;德克萨斯联合保险公司凭借本土州保险公司中最低的损失率，斩获本年度&#39;董事长杯&#39;。&quot;</p></blockquote><p><strong>本土州模式的胜利</strong>——在行业整体崩溃时，单一深耕本地市场的策略，天然具有更好的风险定价能力。</p><h3 id="家庭汽车保险公司换帅" tabindex="-1">家庭汽车保险公司换帅 <a class="header-anchor" href="#家庭汽车保险公司换帅" aria-label="Permalink to &quot;家庭汽车保险公司换帅&quot;">​</a></h3><p>10月，John Seward 出任总裁，对费率定价和营销模式进行了全面改革。公司从6个月期直接账单保单切入，提高了对市场变化的反应速度。</p><p>这是伯克希尔文化的一个经典操作：<strong>在困境中果断换人</strong>，而不是容忍平庸的表现。</p><h2 id="蓝筹印花-被忽视的宝藏" tabindex="-1">蓝筹印花：被忽视的宝藏 <a class="header-anchor" href="#蓝筹印花-被忽视的宝藏" aria-label="Permalink to &quot;蓝筹印花：被忽视的宝藏&quot;">​</a></h2><p>1975年，巴菲特在年报中花了相当篇幅讨论蓝筹印花公司（Blue Chip Stamps）。</p><p>重要数据：</p><ul><li>印花业务规模：1970年峰值的<strong>1/6</strong>（仍在快速萎缩）</li><li>但：<strong>喜诗糖果</strong>（See&#39;s Candies）被证明是&quot;极为成功的投资&quot;</li><li>伯克希尔持股比例：已从25%提升至<strong>31%</strong></li></ul><p>蓝筹印花的价值在于：</p><ol><li>萎缩的印花业务 = 大量浮存金（客户预付款）</li><li>喜诗糖果 = 稳定的高ROE业务</li><li>持股比例持续提升 → 影响力不断扩大</li></ol><h2 id="十年总结-伯克希尔的蜕变" tabindex="-1">十年总结：伯克希尔的蜕变 <a class="header-anchor" href="#十年总结-伯克希尔的蜕变" aria-label="Permalink to &quot;十年总结：伯克希尔的蜕变&quot;">​</a></h2><p>这是巴菲特第一次系统性地回顾1965-1975年（十年）的经营成果：</p><table tabindex="0"><thead><tr><th>指标</th><th>1964年末</th><th>1975年末</th></tr></thead><tbody><tr><td>股东权益</td><td>2210万美元</td><td>9290万美元</td></tr><tr><td>流通股</td><td>1,137,778股</td><td>979,569股</td></tr><tr><td>股价（账面）</td><td>$19.46</td><td>$94.92</td></tr><tr><td>年均复合增长</td><td>—</td><td><strong>~15%</strong></td></tr></tbody></table><blockquote><p>&quot;十年间，我们通过现金（或现金加票据）收购了六家企业，自主创办了四家，购入了一家大型关联企业31%的股权，同时将流通股缩减14%。&quot;</p></blockquote><p><strong>但巴菲特同时承认</strong>：纺织业务10年净赚&quot;不足零&quot;。所有超额回报，都来自资本重新配置——将纺织业务创造的现金，配置到了银行、保险和优秀企业。</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><p><strong>洞察一：所得税退税是虚假利润</strong></p><p>1975年的利润中有&quot;很大一部分&quot;来自联邦所得税退税——因为保险业务亏损带来了税务收益。但这不可持续，意味着1976年的利润压力更大。</p><p>巴菲特选择如实告知，不粉饰太平。</p><p><strong>洞察二：持股比例从25%到31%——逐步控股的策略</strong></p><p>在蓝筹印花上，伯克希尔持股从25%逐步提升至31%。不是一次性控股，而是通过持续增持，逐步扩大影响力。这是后来持续30年的&quot;蓝筹印花→伯克希尔&quot;合并之路的起点。</p><p><strong>洞察三：果断换人是困境反转的关键</strong></p><p>John Seward 在10月临危受命，对家庭汽车保险公司进行了全面改革。伯克希尔的文化是：<strong>容忍客观环境的困难，但不容忍能力的不足</strong>。换人是常态，不是失败。</p><h2 id="历史坐标" tabindex="-1">历史坐标 <a class="header-anchor" href="#历史坐标" aria-label="Permalink to &quot;历史坐标&quot;">​</a></h2><ul><li>距离1956年巴菲特合伙基金：<strong>19年</strong></li><li>距离1965年接手伯克希尔：<strong>10年</strong></li><li>这是十年回顾的节点——年均复合增长约15%，但ROE仅7.6%</li><li><strong>黎明前最后的黑暗</strong>：1976年即将迎来显著反弹</li></ul>',42)])])}const g=a(d,[["render",l]]);export{q as __pageData,g as default};
